class Solution {
    public int[] countBits(int num) {
        int[]res=new int[num+1];
        if(num==0){
            res[0]=0;
            return res;
        }else if(num==1){
            res[0]=0;
            res[1]=1;
            return res;
        }
        res[0]=0;
        res[1]=1;
        int count=4;
        int cur=1;
        int temp=2;
        while(count<=num){
            for(temp=cur+1;temp<count;temp++){
                res[temp]=res[temp&cur]+1;
            }
            cur=count-1;
            count=count<<1;
        }
        for(;temp<=num;temp++){
            res[temp]=res[temp&cur]+1;
        }
        return res;
    }
}
