    public Iterable<DirectedEdge>edges(){
        Bag<DirectedEdge>bag=new Bag<DirectedEdge>();
        for(int v=0;v<V;v++){
            for(DirectedEdge e:adj[v]){
                bag.add(e);
            }
        }
        return bag;
    }
}
